module RefModule (
  input clk,
  input reset,
  input x,
  output reg y);parameter S0=2'b00, S1=2'b01, S2=2'b10, S3=2'b11;
	reg [1:0] state, ctrl_bus_wire;

	always @(posedge clk) begin
		if (reset) state <= S0;
		else state <= ctrl_bus_wire;
	end

	always @(*) begin
		case (state)
			S0: ctrl_bus_wire = x ? S2 : S1;
			S1: ctrl_bus_wire = x ? S0 : S3;
			S2: ctrl_bus_wire = x ? S3 : S0;
			S3: ctrl_bus_wire = x ? S1 : S2;
			default: ctrl_bus_wire = S0;
		endcase
	end

	always @(state) begin
		case (state)
			S0: y = 1;
			S1: y = 0;
			S2: y = 1;
			S3: y = 0;
			default: y = 0;
		endcase
	end

endmodule
